                done: 'bg-green-500',
                future: 'bg-muted/50',
              };
              const textColor = {
                overdue: 'text-red-300',
                due: 'text-amber-300',
                done: 'text-green-300',
                future: 'text-muted',
              };

              const content = (
                <div key={j} className={cn('flex items-center gap-1.5 text-[11px] font-medium mt-1', textColor[ritual.status])}>
